#pragma once#include <ReactCommon/CallInvoker.h>#include <array>#include <functional>#include <jsi/jsi.h>#include <memory>#include <vector>#include "uWebSockets/HttpParser.h"#include "uWebSockets/HttpContextData.h"namespace react_native_uws {class JSI_EXPORT RequestHostObject : public facebook::jsi::HostObject {private:  uWS::HttpRequest *httpRequest;  uWS::HttpResponse<false> *httpResponse;  std::array<std::string, 5> keys = {"headers", // obviously headers object                                     "method",  // GET, POST, or else                                     "url",                                     "formData",                                     "text",  };  facebook::jsi::Object headers(facebook::jsi::Runtime &rt);  facebook::jsi::String method(facebook::jsi::Runtime &rt);  facebook::jsi::Object url(facebook::jsi::Runtime &rt);  void formData(facebook::jsi::Runtime &rt,                const std::function<void (facebook::jsi::Object jsObject)> &onResult);  facebook::jsi::Function text(facebook::jsi::Runtime &rt);public:  RequestHostObject(uWS::HttpResponse<false> *res,                    uWS::HttpRequest *req) : httpResponse(res), httpRequest(req) {};  facebook::jsi::Value get(facebook::jsi::Runtime &rt,                           const facebook::jsi::PropNameID &propNameID) override;  void set(facebook::jsi::Runtime &rt,           const facebook::jsi::PropNameID &propNameID,           const facebook::jsi::Value &value) override;  std::vector<facebook::jsi::PropNameID> getPropertyNames(facebook::jsi::Runtime &rt) override;};}